    # Git init (act needs a git repo)
    Push-Location $dir
    try {
        git init -q -b main
        git config user.email 'ci@example.com'
        git config user.name 'ci'
        git add -A
        git commit -q -m 'test fixture'
    } finally { Pop-Location }
    return $dir
